let rows: Vec<Row> = app.entries.iter().skip(app.scroll_offset).take(10).map(|e| { Row::new(vec![ Cell::from(e.rank.to_string()), Cell::from(e.hotkey.clone()), Cell::from(e.github.clone()), Cell::from(format!("{:.2}", e.net_points)), Cell::from(e.valid.to_string()), Cell::from(e.invalid.to_string()), Cell::from(e.stars.to_string()), Cell::from(format!("{:.4}", e.weight)), ]) }).collect(); let table = Table::new(rows, widths).header(header).block(Block::default().borders(Borders::ALL).border_style(Style::default().fg(Color::Cyan)).title(title)).row_highlight_style(Style::default().bg(Color::DarkGray)); frame.render_widget(table, chunks[0]);